import{_ as e,o as a,c as t,a2 as i}from"./chunks/framework.IwO0Hdn_.js";const p=JSON.parse('{"title":"[LOGIC / BUSINESS] F-02.8 — Estado del Log (Activo / Solucionado)","description":"","frontmatter":{},"headers":[],"relativePath":"backlog/F-02.8_estado_log_solucionado.md","filePath":"backlog/F-02.8_estado_log_solucionado.md","lastUpdated":null}'),c={name:"backlog/F-02.8_estado_log_solucionado.md"};function n(s,o,d,l,r,u){return a(),t("div",null,[...o[0]||(o[0]=[i('<h1 id="logic-business-f-02-8-—-estado-del-log-activo-solucionado" tabindex="-1">[LOGIC / BUSINESS] F-02.8 — Estado del Log (Activo / Solucionado) <a class="header-anchor" href="#logic-business-f-02-8-—-estado-del-log-activo-solucionado" aria-label="Permalink to &quot;[LOGIC / BUSINESS] F-02.8 — Estado del Log (Activo / Solucionado)&quot;">​</a></h1><p><strong>Épica:</strong> EPIC-02 — Listado y Filtrado de Logs Activos</p><h2 id="🏷️-categoria" tabindex="-1">🏷️ Categoría <a class="header-anchor" href="#🏷️-categoria" aria-label="Permalink to &quot;🏷️ Categoría&quot;">​</a></h2><p><strong>Categoría:</strong> <code>Logic / Business</code><strong>Secundaria:</strong> <code>UI / Presentation</code><strong>Impacta en:</strong> Equipo Fullstack (Livewire + Laravel)</p><h2 id="📦-dependencias" tabindex="-1">📦 Dependencias <a class="header-anchor" href="#📦-dependencias" aria-label="Permalink to &quot;📦 Dependencias&quot;">​</a></h2><blockquote><p>Backlogs que deben estar <strong>completados</strong> antes de implementar esta feature.</p></blockquote><table tabindex="0"><thead><tr><th>Backlog</th><th>Motivo</th></tr></thead><tbody><tr><td><a href="./F-02.1_tabla_logs_paginada.html">F-02.1</a></td><td>Componente <code>LogsTable</code> donde se añade el botón &#39;Solucionado&#39;</td></tr><tr><td><a href="./F-03.1_detalle_log.html">F-03.1</a></td><td>Vista detalle del log donde también aparece el botón</td></tr></tbody></table><p><strong>Prioridad:</strong> <code>Should</code></p><hr><p><strong>Descripción:</strong> Como administrador del sistema Quiero marcar un log como &quot;Solucionado&quot; con un clic rápido desde la tabla o el detalle Para que desaparezca de la vista de logs activos sin necesidad de archivarlo en el histórico con un comentario detallado</p><p><strong>Criterios de Aceptación (Checklist):</strong></p><ul><li>[ ] <strong>Escenario 1 (Marcar como solucionado):</strong> Dado que veo un log activo en la tabla, cuando pulso el botón &quot;Solucionado&quot; (icono de check), entonces el log cambia su estado a <code>solucionado</code> y desaparece de la lista de activos sin recargar la página.</li><li>[ ] <strong>Escenario 2 (Modal de confirmación):</strong> Dado que pulso &quot;Solucionado&quot;, cuando se ejecuta la acción, entonces se muestra un modal de confirmación (Alpine.js <code>x-show</code>) antes de proceder para evitar clics accidentales.</li><li>[ ] <strong>Escenario 3 (Sin comentario obligatorio):</strong> Dado que marco un log como solucionado, cuando se confirma, entonces no se requiere comentario ni descripción — la acción es inmediata (diferente del archivado en histórico).</li><li>[ ] <strong>Escenario 4 (Diferencia con histórico):</strong> Dado que existen dos acciones sobre un log activo (&quot;Guardar en Histórico&quot; y &quot;Solucionado&quot;), cuando el admin abre el detalle, entonces ambos botones son visibles y claramente diferenciados.</li><li>[ ] <strong>Escenario 5 (Campo en DB):</strong> El campo <code>archived</code> de la tabla <code>logs</code> se usa como estado: <code>false</code> = activo, <code>true</code> = solucionado/archivado. El panel filtra automáticamente <code>WHERE archived = false</code> en la vista de activos.</li><li>[ ] <strong>Requisito Técnico:</strong> Livewire Action <code>markAsSolved(id)</code> en el componente <code>LogsTable</code> o <code>LogDetail</code>. Ejecuta <code>UPDATE logs SET archived = true WHERE id = ?</code> mediante Eloquent. El componente se re-renderiza y el log desaparece de la lista.</li></ul><hr><p><strong>MoSCoW:</strong> <code>SHOULD</code><strong>Sprint:</strong> Sprint 2</p><p><strong>Notas:</strong></p><ul><li>Esta acción es un &quot;soft close&quot; rápido. El log NO pasa al histórico ni genera entrada en <code>archived_logs</code>.</li><li>Si se quiere preservar el log en el histórico con comentarios, se usa el botón &quot;Guardar en Histórico&quot; (F-03.2).</li><li>El campo <code>logs.archived = true</code> es el mismo que se usa al archivar — ambas acciones hacen que el log deje de aparecer en la vista activa.</li></ul>',16)])])}const m=e(c,[["render",n]]);export{p as __pageData,m as default};
